import React, { useState, useEffect, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import AuthContext from '../context/AuthContext';
import { userAPI, bookingAPI, ticketAPI, resourceAPI } from '../services/api';
import '../styles/AdminDashboard.css';

const AdminDashboard = () => {
  const { user } = useContext(AuthContext);
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('users');
  const [loading, setLoading] = useState(true);
  
  // Users Management
  const [users, setUsers] = useState([]);
  const [userForm, setUserForm] = useState({ email: '', password: '', fullName: '', role: 'USER' });
  
  // Bookings Management
  const [bookings, setBookings] = useState([]);
  const [bookingFilter, setBookingFilter] = useState('ALL');
  
  // Tickets Management
  const [tickets, setTickets] = useState([]);
  const [ticketFilter, setTicketFilter] = useState('OPEN');
  
  // Resources Management
  const [resources, setResources] = useState([]);
  const [resourceForm, setResourceForm] = useState({ name: '', type: '', status: 'AVAILABLE' });

  // Stats
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalBookings: 0,
    openTickets: 0,
    totalResources: 0,
  });

  // Fetch Dashboard Data
  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const [bookingsRes, ticketsRes, resourcesRes] = await Promise.all([
          bookingAPI.getAll(),
          ticketAPI.getAll(),
          resourceAPI.getAll(),
        ]);

        setBookings(bookingsRes.data || []);
        setTickets(ticketsRes.data || []);
        setResources(resourcesRes.data || []);

        setStats({
          totalUsers: 100, // Will be updated from API
          totalBookings: bookingsRes.data?.length || 0,
          openTickets: ticketsRes.data?.filter(t => t.status === 'OPEN').length || 0,
          totalResources: resourcesRes.data?.length || 0,
        });
      } catch (error) {
        console.error('Error fetching admin data:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  // Handle Create User
  const handleCreateUser = async (e) => {
    e.preventDefault();
    if (!userForm.email || !userForm.password || !userForm.fullName) {
      alert('Please fill in all fields');
      return;
    }

    try {
      // This would be a new endpoint to create any user (admin only)
      console.log('Creating user:', userForm);
      alert('User creation feature would be implemented with backend support');
      setUserForm({ email: '', password: '', fullName: '', role: 'USER' });
    } catch (error) {
      console.error('Error creating user:', error);
      alert('Failed to create user');
    }
  };

  // Handle Delete Booking
  const handleDeleteBooking = async (bookingId) => {
    if (!window.confirm('Are you sure you want to delete this booking?')) return;
    
    try {
      await bookingAPI.delete(bookingId);
      setBookings(bookings.filter(b => b.id !== bookingId));
      alert('Booking deleted successfully');
    } catch (error) {
      console.error('Error deleting booking:', error);
      alert('Failed to delete booking');
    }
  };

  // Handle Delete Ticket
  const handleDeleteTicket = async (ticketId) => {
    if (!window.confirm('Are you sure you want to delete this ticket?')) return;
    
    try {
      await ticketAPI.delete(ticketId);
      setTickets(tickets.filter(t => t.id !== ticketId));
      alert('Ticket deleted successfully');
    } catch (error) {
      console.error('Error deleting ticket:', error);
      alert('Failed to delete ticket');
    }
  };

  // Handle Delete Resource
  const handleDeleteResource = async (resourceId) => {
    if (!window.confirm('Are you sure you want to delete this resource?')) return;
    
    try {
      await resourceAPI.delete(resourceId);
      setResources(resources.filter(r => r.id !== resourceId));
      alert('Resource deleted successfully');
    } catch (error) {
      console.error('Error deleting resource:', error);
      alert('Failed to delete resource');
    }
  };

  if (loading && activeTab === 'dashboard') {
    return <div className="admin-loading">Loading admin dashboard...</div>;
  }

  return (
    <div className="admin-dashboard">
      {/* Header */}
      <div className="admin-header">
        <h1>Admin Dashboard</h1>
        <p>Welcome, {user?.fullName}</p>
      </div>

      {/* Navigation Tabs */}
      <div className="admin-nav">
        <button 
          className={`admin-nav-btn ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`admin-nav-btn ${activeTab === 'users' ? 'active' : ''}`}
          onClick={() => setActiveTab('users')}
        >
          👥 Users
        </button>
        <button 
          className={`admin-nav-btn ${activeTab === 'bookings' ? 'active' : ''}`}
          onClick={() => setActiveTab('bookings')}
        >
          📅 Bookings
        </button>
        <button 
          className={`admin-nav-btn ${activeTab === 'tickets' ? 'active' : ''}`}
          onClick={() => setActiveTab('tickets')}
        >
          🎫 Tickets
        </button>
        <button 
          className={`admin-nav-btn ${activeTab === 'resources' ? 'active' : ''}`}
          onClick={() => setActiveTab('resources')}
        >
          📦 Resources
        </button>
      </div>

      {/* Content Areas */}
      <div className="admin-content">

        {/* Dashboard Tab */}
        {activeTab === 'dashboard' && (
          <div className="admin-section">
            <h2>System Overview</h2>
            <div className="stats-grid">
              <div className="stat-card">
                <h3>Total Users</h3>
                <p className="stat-number">{stats.totalUsers}</p>
              </div>
              <div className="stat-card">
                <h3>Total Bookings</h3>
                <p className="stat-number">{stats.totalBookings}</p>
              </div>
              <div className="stat-card">
                <h3>Open Tickets</h3>
                <p className="stat-number">{stats.openTickets}</p>
              </div>
              <div className="stat-card">
                <h3>Total Resources</h3>
                <p className="stat-number">{stats.totalResources}</p>
              </div>
            </div>
          </div>
        )}

        {/* Users Tab */}
        {activeTab === 'users' && (
          <div className="admin-section">
            <h2>User Management</h2>
            
            <div className="admin-form">
              <h3>Create New User</h3>
              <form onSubmit={handleCreateUser}>
                <div className="form-row">
                  <div className="form-group">
                    <label>Email</label>
                    <input
                      type="email"
                      value={userForm.email}
                      onChange={(e) => setUserForm({...userForm, email: e.target.value})}
                      placeholder="user@example.com"
                    />
                  </div>
                  <div className="form-group">
                    <label>Full Name</label>
                    <input
                      type="text"
                      value={userForm.fullName}
                      onChange={(e) => setUserForm({...userForm, fullName: e.target.value})}
                      placeholder="Full Name"
                    />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Password</label>
                    <input
                      type="password"
                      value={userForm.password}
                      onChange={(e) => setUserForm({...userForm, password: e.target.value})}
                      placeholder="Password"
                    />
                  </div>
                  <div className="form-group">
                    <label>Role</label>
                    <select
                      value={userForm.role}
                      onChange={(e) => setUserForm({...userForm, role: e.target.value})}
                    >
                      <option value="USER">User</option>
                      <option value="ADMIN">Admin</option>
                    </select>
                  </div>
                </div>
                <button type="submit" className="btn btn-success">Create User</button>
              </form>
            </div>

            <div className="admin-table">
              <h3>Users List</h3>
              <p className="info-text">User management integration with API pending</p>
            </div>
          </div>
        )}

        {/* Bookings Tab */}
        {activeTab === 'bookings' && (
          <div className="admin-section">
            <h2>Booking Management</h2>
            
            <div className="filter-group">
              <label>Filter by Status:</label>
              <select value={bookingFilter} onChange={(e) => setBookingFilter(e.target.value)}>
                <option value="ALL">All Bookings</option>
                <option value="CONFIRMED">Confirmed</option>
                <option value="PENDING">Pending</option>
                <option value="CANCELLED">Cancelled</option>
                <option value="COMPLETED">Completed</option>
              </select>
            </div>

            <div className="admin-table">
              <table>
                <thead>
                  <tr>
                    <th>Booking ID</th>
                    <th>Resource</th>
                    <th>User</th>
                    <th>Start Date</th>
                    <th>End Date</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {bookings.length > 0 ? (
                    bookings.map(booking => (
                      <tr key={booking.id}>
                        <td>{booking.id?.substring(0, 8)}...</td>
                        <td>{booking.resourceId}</td>
                        <td>{booking.userId}</td>
                        <td>{new Date(booking.startDateTime).toLocaleDateString()}</td>
                        <td>{new Date(booking.endDateTime).toLocaleDateString()}</td>
                        <td><span className={`status ${booking.status?.toLowerCase()}`}>{booking.status}</span></td>
                        <td>
                          <button className="btn-small btn-danger" onClick={() => handleDeleteBooking(booking.id)}>Delete</button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr><td colSpan="7">No bookings found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Tickets Tab */}
        {activeTab === 'tickets' && (
          <div className="admin-section">
            <h2>Ticket Management</h2>
            
            <div className="filter-group">
              <label>Filter by Status:</label>
              <select value={ticketFilter} onChange={(e) => setTicketFilter(e.target.value)}>
                <option value="OPEN">Open</option>
                <option value="IN_PROGRESS">In Progress</option>
                <option value="CLOSED">Closed</option>
              </select>
            </div>

            <div className="admin-table">
              <table>
                <thead>
                  <tr>
                    <th>Ticket ID</th>
                    <th>Title</th>
                    <th>Category</th>
                    <th>Priority</th>
                    <th>Status</th>
                    <th>Created By</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {tickets.length > 0 ? (
                    tickets
                      .filter(t => ticketFilter === 'OPEN' || t.status === ticketFilter)
                      .map(ticket => (
                        <tr key={ticket.id}>
                          <td>{ticket.id?.substring(0, 8)}...</td>
                          <td>{ticket.title}</td>
                          <td>{ticket.category}</td>
                          <td><span className={`priority ${ticket.priority?.toLowerCase()}`}>{ticket.priority}</span></td>
                          <td><span className={`status ${ticket.status?.toLowerCase()}`}>{ticket.status}</span></td>
                          <td>{ticket.createdBy}</td>
                          <td>
                            <button className="btn-small btn-danger" onClick={() => handleDeleteTicket(ticket.id)}>Delete</button>
                          </td>
                        </tr>
                      ))
                  ) : (
                    <tr><td colSpan="7">No tickets found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Resources Tab */}
        {activeTab === 'resources' && (
          <div className="admin-section">
            <h2>Resource Management</h2>
            
            <div className="admin-form">
              <h3>Add New Resource</h3>
              <form onSubmit={(e) => {
                e.preventDefault();
                alert('Resource creation feature would be implemented with backend support');
              }}>
                <div className="form-row">
                  <div className="form-group">
                    <label>Resource Name</label>
                    <input
                      type="text"
                      value={resourceForm.name}
                      onChange={(e) => setResourceForm({...resourceForm, name: e.target.value})}
                      placeholder="e.g., Meeting Room A"
                    />
                  </div>
                  <div className="form-group">
                    <label>Type</label>
                    <select
                      value={resourceForm.type}
                      onChange={(e) => setResourceForm({...resourceForm, type: e.target.value})}
                    >
                      <option value="">Select Type</option>
                      <option value="ROOM">Room</option>
                      <option value="EQUIPMENT">Equipment</option>
                      <option value="VEHICLE">Vehicle</option>
                      <option value="OTHER">Other</option>
                    </select>
                  </div>
                </div>
                <button type="submit" className="btn btn-success">Add Resource</button>
              </form>
            </div>

            <div className="admin-table">
              <table>
                <thead>
                  <tr>
                    <th>Resource ID</th>
                    <th>Name</th>
                    <th>Type</th>
                    <th>Status</th>
                    <th>Capacity</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {resources.length > 0 ? (
                    resources.map(resource => (
                      <tr key={resource.id}>
                        <td>{resource.id?.substring(0, 8)}...</td>
                        <td>{resource.name}</td>
                        <td>{resource.type}</td>
                        <td><span className={`status ${resource.status?.toLowerCase()}`}>{resource.status}</span></td>
                        <td>{resource.capacity || 'N/A'}</td>
                        <td>
                          <button className="btn-small btn-danger" onClick={() => handleDeleteResource(resource.id)}>Delete</button>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr><td colSpan="6">No resources found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
